const designImportMigration=require("../../../../../../design_import_migration");const _kgb_=designImportMigration.getMxgoUtils().getKgbGlobal();const agentsUtils=require("./agentsUtils");class AgentBtnSimpleActionSnippet{getId(t){let e=[];e.push(t);e.push(_kgb_.modules.utils.getKUID().toString());return e.join("_")}constructor(){this.setDefault()}setDefault(){this.addSnippetAction={id:this.getId("ADD_SNIPPET"),codeSnippet:"alert('this is not yet supported')",type:"ADD_SNIPPET"}}setAddSnippetCode(t,e,i,n){var s="";var s=agentsUtils?.codeSnippetSrcForIntService(e.servicename,t.name,n);this.addSnippetAction.codeSnippet=s}toActions(){return[this.addSnippetAction]}}module.exports={AgentBtnSimpleActionSnippet:AgentBtnSimpleActionSnippet};